CODE_EXAMPLE:
public class ShardManager {
  private int shardCount = 4;

  public int GetShard(string key) {
    int hash = key.GetHashCode();
    return Math.Abs(hash % shardCount);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void GetShard_ReturnsShard_WithinRange() {
  var manager = new ShardManager();
  int shard = manager.GetShard("user123");
  Assert.IsTrue(shard >= 0 && shard < 4);
}

[TestMethod]
public void GetShard_IsDeterministic() {
  var manager = new ShardManager();
  int shard1 = manager.GetShard("key");
  int shard2 = manager.GetShard("key");
  Assert.AreEqual(shard1, shard2);
}
